def get_user_name(user):
    # get user name
    return user


def increment_counter(counter):
    # increment counter
    counter += 1
    return counter


def validate_input_data(input_val, data):
    # validate input data
    if not data:
        return False
    return True


def calculate_total_price(total, price):
    # calculate total price
    return total + price
